mapper.select:
SELECT er.id, er.report_no AS reportNo, er.emp_id AS empId, er.total_amount AS totalAmount, er.expense_type AS expenseType, er.invoice_url AS invoiceUrl, er.description, er.status, er.create_time AS createTime, ee.name AS empName, sd.dept_name AS deptName FROM expense_report er LEFT JOIN emp_employee ee ON er.emp_id = ee.id LEFT JOIN sys_dept sd ON ee.dept_id = sd.id
AND er.status = #{status}
ORDER BY er.create_time DESC
